base = "/var/www/felia-home-web/public"
for path, b64 in data.items():
    full = os.path.join(base, path)
    os.makedirs(os.path.dirname(full), exist_ok=True)
    with open(full, "wb") as f:
        f.write(base64.b64decode(b64))
    print(f"OK {path}")
print("完了")
